#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* newNode(int key) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = key;
    node->left = node->right = NULL;
    return node;
}

// Function to find the floor and ceiling of a target value in a BST
void findFloorCeiling(Node* root, int target, int* floor, int* ceiling) {
    if (root == NULL) return;

    if (root->val == target) {
        *floor = *ceiling = root->val;
        return;
    }

    if (root->val < target) {
        *floor = root->val;
        findFloorCeiling(root->right, target, floor, ceiling);
    } else {
        *ceiling = root->val;
        findFloorCeiling(root->left, target, floor, ceiling);
    }
}

int main() {
    // Create a sample BST
    Node* root = newNode(8);
    root->left = newNode(3);
    root->right = newNode(10);
    root->left->left = newNode(1);
    root->left->right = newNode(6);
    root->left->right->left = newNode(4);
    root->left->right->right = newNode(7);
    root->right->right = newNode(14);
    root->right->right->left = newNode(13);

    int target = 4.428571;
    int floor = -1, ceiling = -1;
    findFloorCeiling(root, (int)target, &floor, &ceiling);

    printf("Floor: %d, Ceiling: %d\n", floor, ceiling);

    return 0;
}

