    static class Node {
        int val;
        Node left;
        Node right;

        Node(int key) {
            val = key;
            left = right = null;
        }
    }

    // Function to find the floor and ceiling of a target value in a BST
    public static void findFloorCeiling(Node root, int target, int[] floor, int[] ceiling) {
        if (root == null) return;

        if (root.val == target) {
            floor[0] = ceiling[0] = root.val;
            return;
        }

        if (root.val < target) {
            floor[0] = root.val;
            findFloorCeiling(root.right, target, floor, ceiling);
        } else {
            ceiling[0] = root.val;
            findFloorCeiling(root.left, target, floor, ceiling);
        }
