class Node {
    constructor(key) {
        this.val = key;
        this.left = null;
        this.right = null;
    }
}

// Function to find the floor and ceiling of a target value in a BST
function findFloorCeiling(root, target) {
    let floor = null;
    let ceiling = null;

    while (root) {
        if (root.val === target) {
            floor = ceiling = root.val;
            break;
        } else if (root.val < target) {
            floor = root.val;
            root = root.right;
        } else {
            ceiling = root.val;
            root = root.left;
        }
    }

    return [floor, ceiling];
}

// Create a sample BST
