root.left.right.right = new Node(7);
root.right.right = new Node(14);
root.right.right.left = new Node(13);

let target = 4;
let [floor, ceiling] = findFloorCeiling(root, target);
console.log(`Floor: ${floor}, Ceiling: ${ceiling}`);

